message.content:
You are reviewing TypeScript type changes for migrating InvoiceCashbackOnboarding screen from Redux to Zustand.

## Task
Review the Models/index.ts file changes to ensure the Props type is correctly updated for Zustand hook pattern.

## Original file:
```typescript
import { PropsIconsNameCore, PropsTokenColorsCore } from "@semparar/design-system-app";
import { TextIconType } from "@semparar/design-system-app/src/atomic/molecules/TextIcon/Models";
import { ScreenProps } from "../../../routes/Models";
import { mapDispatchToProps, mapStateToProps } from '..';

export interface InvoiceCashbackViewProps {
  items: InformationList[];
  hasError: boolean;
  hasLoading: boolean;
  handleGoBack: () => void;
  handleContinue: () => void;
  handleRetry: () => void;
  cashbackInvoiceList?: CashbackInvoiceItem[];
  pts: number;
  price?: number;
  pointsQuantity?: number;
  conversionFactor?: number;
  isLoadingParameterization?: boolean;
  width: number;
}

export interface InvoiceCashbackProps
  extends ScreenProps<
    'InvoiceCashbackOnboarding',
    typeof mapStateToProps,
    typeof mapDispatchToProps
  > {}

export interface CashbackInvoiceItem {
  text?: string;
  type: TextIconType;
  icon: PropsIconsNameCore;
  iconColor: PropsTokenColorsCore;
  iconColorShape: PropsTokenColorsCore;
  description: string;
}

export type InformationList = {
  type: string,
  icon: string,
  iconColor: string,
  iconColorShape: string,
  description: string
}
```

## New file:
```typescript
import { PropsIconsNameCore, PropsTokenColorsCore } from "@semparar/design-system-app";
